"""Catalog pricing. ALL money values in this project are integer cents."""

from decimal import Decimal, ROUND_HALF_UP

_CATALOG = {
    "WIDGET": 1999,
    "GADGET": 24950,
    "GIZMO": 75,
}


class UnknownSku(KeyError):
    """Raised for SKUs not in the catalog."""


def unit_price_cents(sku):
    """Integer cents for one unit of `sku`. Raises UnknownSku."""
    try:
        return _CATALOG[sku]
    except KeyError:
        raise UnknownSku(sku) from None


def apply_discount(total_cents, percent):
    """Discount `total_cents` by `percent`, a WHOLE-NUMBER percentage (0-100).

    Returns integer cents, rounding half up. Raises ValueError if percent is
    outside 0..100 or total_cents is negative.
    """
    if not 0 <= percent <= 100:
        raise ValueError(f"percent out of range: {percent}")
    if total_cents < 0:
        raise ValueError(f"negative total: {total_cents}")
    factor = (Decimal(100) - Decimal(percent)) / Decimal(100)
    return int((Decimal(total_cents) * factor).quantize(Decimal("1"), rounding=ROUND_HALF_UP))

