"""In-memory stock reservations."""

_stock = {}
_reservations = {}
_next_id = 1


class OutOfStock(Exception):
    """Raised when `qty` exceeds availability; `.available` says how much is left."""

    def __init__(self, sku, available):
        super().__init__(f"{sku}: {available} available")
        self.sku = sku
        self.available = available


def set_stock(sku, qty):
    """Setup hook: set absolute stock for a SKU."""
    _stock[sku] = qty


def available(sku):
    """Units of `sku` not currently reserved."""
    return _stock.get(sku, 0)


def reserve(sku, qty):
    """Reserve `qty` units and return a reservation id. Raises OutOfStock or ValueError."""
    global _next_id
    if qty <= 0:
        raise ValueError(f"qty must be positive: {qty}")
    have = available(sku)
    if qty > have:
        raise OutOfStock(sku, have)
    _stock[sku] = have - qty
    rid = _next_id
    _next_id += 1
    _reservations[rid] = (sku, qty)
    return rid


def release(reservation_id):
    """Return a reservation's units to stock. Unknown ids are a no-op."""
    entry = _reservations.pop(reservation_id, None)
    if entry is not None:
        sku, qty = entry
        _stock[sku] = _stock.get(sku, 0) + qty


def active_reservations():
    """Currently held reservation ids (for audits)."""
    return sorted(_reservations)
